// Scrub & structure the external feed into the schema Spark Structured
// Streaming expects on the `steel_market_prices` topic.
// Output one Kafka-ready message per item.
const today = new Date().toISOString().slice(0, 10);
const out = [];

for (const item of $input.all()) {
  const src = item.json || {};
  // Defensive extraction with fallbacks; coerce to numbers.
  const num = (v, d = null) => {
    const n = Number(v);
    return Number.isFinite(n) ? n : d;
  };

  const record = {
    date: src.date || today,
    steel_price_egypt_egp: num(src.rebar_egp ?? src.rebar?.egp),
    iron_ore_price_usd:    num(src.iron_ore_usd ?? src.iron_ore?.usd),
    scrap_price_usd:       num(src.scrap_usd ?? src.scrap?.usd),
    coking_coal_price_usd: num(src.coking_coal_usd ?? src.coking_coal?.usd),
    billet_price_usd:      num(src.billet_usd ?? src.billet?.usd),
    usd_egp_rate:          num(src.usd_egp ?? src.fx?.usd_egp),
    source: src.source || 'example-steel-index',
    harvested_at: new Date().toISOString()
  };

  // Drop the message if the core price is missing — never publish garbage.
  if (record.steel_price_egypt_egp === null && record.iron_ore_price_usd === null) {
    continue;
  }
  out.push({ json: record });
}

if (out.length === 0) {
  // Surface an empty harvest as an error so the run is visibly failed.
  throw new Error('Market harvest produced no valid records — upstream feed may be down.');
}
return out;
